before_code:
entity comparator_64bit is
  port (
    data_a : in std_logic_vector(63 downto 0);
    data_b : in std_logic_vector(63 downto 0);
    gt : out std_logic;
    eq : out std_logic;
    lt : out std_logic
  );
end entity comparator_64bit;

architecture rtl of comparator_64bit is
begin
  process(data_a) is
  begin
    if (data_a > data_b) then
      gt <= '1';
      eq <= '0';
      lt <= '0';
    elsif (data_a = data_b) then
      gt <= '0';
      eq <= '1';
      lt <= '0';
    else
      gt <= '0';
      eq <= '0';
      lt <= '1';
    end if;
  end process;
end architecture rtl;

after_code:
entity comparator_64bit is
  port (
    data_a : in std_logic_vector(63 downto 0);
    data_b : in std_logic_vector(63 downto 0);
